1	import type { FastifyPluginAsync } from 'fastify'
2	
3	interface HealthResponse {
4	  status: string
5	  message: string
6	  timestamp: string
7	}
8	
9	const healthRoutes: FastifyPluginAsync = async (fastify) => {
10	  fastify.get('/health/live', {
11	    config: { compress: false, rateLimit: false },
12	    schema: {
13	      summary: 'Liveness probe',
14	      tags: ['health'],
15	      response: {
16	        200: { type: 'object', properties: { status: { type: 'string' } } }
17	      }
18	    }
19	  }, async (_, reply) => {
20	    reply.header('Cache-Control', 'no-store')
21	    return { status: 'ok' }
22	  })
23	
24	  fastify.get('/health/ready', {
25	    config: { compress: false, rateLimit: false },
26	    schema: {
27	      summary: 'Readiness probe',
28	      tags: ['health'],
29	      response: {
30	        200: { type: 'object', properties: { status: { type: 'string' } } },
31	        503: { type: 'object', properties: { status: { type: 'string' } } }
32	      }
33	    }
34	  }, async (_, reply) => {
35	    reply.header('Cache-Control', 'no-store')
36	    if (!fastify.server.listening) {
37	      return reply.code(503).send({ status: 'not_ready' })
38	    }
39	    return { status: 'ready' }
40	  })
41	
42	  fastify.get<{ Reply: HealthResponse }>('/health', {
43	    config: { compress: false, rateLimit: false },
44	    schema: {
45	      summary: 'Health check (legacy)',
46	      tags: ['health'],
47	      response: {
48	        200: {
49	          type: 'object',
50	          properties: {
51	            status: { type: 'string' },
52	            message: { type: 'string' },
53	            timestamp: { type: 'string' }
54	          }
55	        }
56	      }
57	    }
58	  }, async (_, reply) => {
59	    reply.header('Cache-Control', 'no-store')
60	    return { status: 'healthy', message: 'API is running', timestamp: new Date().toISOString() }
61	  })
62	}
63	
64	export default healthRoutes
