1	import type { FastifyPluginAsync } from 'fastify'
2	import { createProblemDetail } from '../errors.js'
3	
4	interface Item {
5	  name: string
6	  description?: string
7	  price: number
8	}
9	
10	const apiRoutes: FastifyPluginAsync = async (fastify) => {
11	  fastify.get('/hello', {
12	    schema: { summary: 'Hello endpoint', tags: ['api'] }
13	  }, async () => {
14	    return { message: 'Hello from Fastify!' }
15	  })
16	
17	  fastify.post<{ Body: Item }>('/items', {
18	    config: { rateLimit: { max: 30, timeWindow: '1 minute' } },
19	    schema: {
20	      summary: 'Create an item',
21	      tags: ['items'],
22	      body: {
23	        type: 'object',
24	        additionalProperties: false,
25	        required: ['name', 'price'],
26	        properties: {
27	          name: { type: 'string', maxLength: 255 },
28	          description: { type: 'string', maxLength: 1000 },
29	          price: { type: 'number', minimum: 0 }
30	        }
31	      }
32	    }
33	  }, async (request) => {
34	    return { status: 'created', item: request.body }
35	  })
36	
37	  fastify.get<{ Params: { id: string } }>('/items/:id', {
38	    schema: {
39	      summary: 'Get item by ID',
40	      tags: ['items'],
41	      params: { type: 'object', properties: { id: { type: 'string' } } }
42	    }
43	  }, async (request, reply) => {
44	    const { id } = request.params
45	    const numId = parseInt(id, 10)
46	
47	    if (isNaN(numId) || numId <= 0) {
48	      return reply
49	        .code(404)
50	        .header('Content-Type', 'application/problem+json')
51	        .send(createProblemDetail(404, 'Not Found', `Item with id '${id}' was not found.`, request.url))
52	    }
53	
54	    return { item_id: numId, name: `Item ${id}`, price: 99.99 }
55	  })
56	}
57	
58	export default apiRoutes
