1	import { FastifyPluginAsync } from 'fastify'
2	import { decodeCursor, encodeCursor, paginatedResponse, paginationQuerySchema } from '../../pagination.js'
3	
4	// When /v2 is released, add to onSend hook:
5	// reply.header('Deprecation', 'true')
6	// reply.header('Sunset', 'Sat, 01 Jan 2027 00:00:00 GMT')
7	// reply.header('Link', '</v2/status>; rel="successor-version"')
8	
9	interface CreateItemBody {
10	  name: string
11	  price: number
12	}
13	
14	const v1Routes: FastifyPluginAsync = async (fastify) => {
15	  // GET routes inherit the global 100 req/min default — read-only, no override needed
16	  fastify.get('/status', {
17	    config: { compress: false },
18	    schema: {
19	      summary: 'API v1 status',
20	      tags: ['v1'],
21	      response: {
22	        200: {
23	          type: 'object',
24	          properties: {
25	            version: { type: 'string' },
26	            status: { type: 'string' },
27	            timestamp: { type: 'string' }
28	          }
29	        }
30	      }
31	    }
32	  }, async () => ({
33	    version: '1',
34	    status: 'ok',
35	    timestamp: new Date().toISOString()
36	  }))
37	
38	  // GET /items: cursor-based pagination over a stub item list
39	  fastify.get<{ Querystring: { limit?: number; cursor?: string } }>('/items', {
40	    schema: {
41	      summary: 'List v1 items',
42	      tags: ['v1'],
43	      querystring: paginationQuerySchema
44	    }
45	  }, async (request) => {
46	    const { limit = 20, cursor } = request.query
47	    const after = cursor ? decodeCursor(cursor) : null
48	    const allItems = Array.from({ length: 50 }, (_, i) => ({
49	      id: i + 1,
50	      name: `Item ${i + 1}`,
51	      price: parseFloat(((i + 1) * 9.99).toFixed(2))
52	    }))
53	    const startId = (after?.id as number) ?? 0
54	    const filtered = allItems.filter(item => item.id > startId)
55	    const page = filtered.slice(0, limit)
56	    const nextCursor = filtered.length > limit ? encodeCursor({ id: page[page.length - 1].id }) : null
57	    return paginatedResponse(page, nextCursor)
58	  })
59	
60	  // POST routes that mutate state: enforced 30 req/min (tighter than global 100)
61	  fastify.post<{ Body: CreateItemBody }>('/items', {
62	    config: { rateLimit: { max: 30, timeWindow: '1 minute' } },
63	    schema: {
64	      summary: 'Create a v1 item',
65	      tags: ['v1'],
66	      body: {
67	        type: 'object',
68	        additionalProperties: false,
69	        required: ['name', 'price'],
70	        properties: {
71	          name: { type: 'string', maxLength: 255 },
72	          price: { type: 'number', minimum: 0 }
73	        }
74	      },
75	      response: {
76	        200: {
77	          type: 'object',
78	          properties: {
79	            status: { type: 'string' },
80	            item: {
81	              type: 'object',
82	              properties: {
83	                name: { type: 'string' },
84	                price: { type: 'number' }
85	              }
86	            }
87	          }
88	        }
89	      }
90	    }
91	  }, async (request) => {
92	    return { status: 'created', item: request.body }
93	  })
94	}
95	
96	export default v1Routes
